var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_NORMAL","text":{"KOREA":"크윽…! 꼼짝 할 수가 없잖아.","JPN":"くっ……！　動けない。","ENG":"Kgh...! I can't move.","TWN":"咳咳……！身體動不了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"볼일 끝날 때까지 벽에 얌전히 붙어 있어.","JPN":"ことが済むまで大人しく壁にへばりついててね。","ENG":"Stick to the wall until I take care of my business.","TWN":"在我把事情辦完之前給我乖乖面壁罰站。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"날 우주로 내쫓으려 한 벌이야.","JPN":"あたしを宇宙に追い出そうとした罰だ。","ENG":"That's for trying to expel me to space.","TWN":"這是你把我扔到太空的懲罰。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_NPC_PRISONER_NORMAL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"따라붙는 녀석들은 대충 처리했네. 이제 내려가자.","JPN":"追手は適当に処理したようだね。もう降りよう。","ENG":"We took care of most of the ones coming after us. Let's head down now.","TWN":"追來的傢伙們已經差不多給我解決了，下去吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"마음대로 해라. 난 이곳에 볼일이 남아있으니까.","JPN":"勝手にしろ。私はまだここに用がある。","ENG":"Do as you please. I still have matters to attend to here.","TWN":"你隨意，我在這裡還有事情要做。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아까도 물어보고 싶었는데 말이야.","JPN":"さっきも聞きたかったんだけど。","ENG":"I wanted to ask you earlier.","TWN":"我之前就想問這個問題了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이렇게까지 아케론을 뒤집어 엎어가면서까지 찾으려는 게 대체 뭐야?","JPN":"アケロンをめちゃくちゃにしてまで探したいものっていったい何？","ENG":"But what's so important that you'd create chaos all across Acheron to find it?","TWN":"你來黃泉到底是想要找什麼東西？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너에게 그런 걸 답해줄 의무가 있나?","JPN":"私がそれを答える義務があるのか？","ENG":"I don't believe I'm obligated to answer that.","TWN":"我有義務回答你的問題嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우린 적이다. 나중에 만났을 때도 너와 협력할 거란 착각은 마라.","JPN":"私たちは敵同士だ。次会ったときにもお前に協力すると思うな。","ENG":"We're enemies. Don't expect me to cooperate the next time we meet.","TWN":"我們是敵人。別以為下次見面還會和你聯手。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하지만, 방금처럼 필요할 땐 서로 이용할 순 있다는 거잖아?","JPN":"でも、今みたいに必要だったらお互い利用できるってことでしょ？","ENG":"But you're open to using each other when necessary, right?","TWN":"但在需要的時候我們還是可以互相利用的，不是嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"당신이 말하면, 나도 내가 알고 있는 정보를 알려 줄게. 어때?","JPN":"あんたが言ってくれれば、あたしも知ってる情報を教えてあげる。どう？","ENG":"If you answer my question, I'll give you information too. What do you say?","TWN":"你如果回答，我也會告訴你一個你想知道的情報，如何？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"거절하지.","JPN":"断る。","ENG":"I refuse.","TWN":"我拒絕。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쳇, 단호하긴.","JPN":"チッ、頑固だな。","ENG":"Tsk, stubborn.","TWN":"嘖，你太固執了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가이드. 취급이 특별한 죄수를 가둘만한 장소가 더 있나?","JPN":"ガイド。他に特別待遇の囚人を収容できそうなところはあるか？","ENG":"Guide. Are there more areas that hold special prisoners?","TWN":"小幫手。這裡還有沒有其他用來囚禁特殊囚犯的場所？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"제가 아는 선에선 그렇습니다.","JPN":"僕の知る限り、あります。","ENG":"Yes, as far as I know.","TWN":"據我所知，確實有。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"어쩌면 일반 수감동에 당신이 찾는 사람이 있을지도 모르죠.","JPN":"でも一般収容棟にあなたの探している人がいるかもしれません。","ENG":"Or, the person you're looking for might be in the normal section.","TWN":"也許你要找的人在普通牢房。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그 사람의 이름을 알려 주시면 제가 가서…","JPN":"その人の名前を教えてもらえたら、僕が行って……","ENG":"If you tell me her name, I can go and–","TWN":"把她的名字告訴我，我會幫你去……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"관리국은 절대로 그 녀석을 남들과 쉽게 접촉할 수 있는 곳에 두지 않을 거다.","JPN":"管理局は絶対あいつを他人と容易く接触できる場所に置かないはずだ。","ENG":"The Administration would never leave her in a place where she could be in contact with others.","TWN":"管理局絕不會把她關在容易與他人接觸的地方。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"우와, 그쪽이 그런 말을 진지하게 할 정도면 엄청 위험한 녀석이긴 한가 보네.","JPN":"うわ、あんたが言うんだから、めっちゃ危ない奴なんだろうね。","ENG":"Wow. This person must be really dangerous for you to say that.","TWN":"哇，連你也這麼說，說明那個人是一個超級危險分子。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"애초에 그런 위험한 녀석을 관리국이 왜 몰래 숨기는진 모르겠지만.","JPN":"そもそもなんでそんな危険な奴を管理局が隠してるんだ？","ENG":"Not that I know why the Administration would hide that kind of dangerous person of interest in the first place.","TWN":"我不明白管理局為什麼要把這麼危險的傢伙偷偷藏起來。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRONE_NPC_PRSIONER_AID","text":{"KOREA":"위험구역 내 생존자 발견. 도움이 필요하십니까?","JPN":"危険区域内に生存者発見。助けが必要ですか？","ENG":"Survivor detected in the danger zone. Do you require assistance?","TWN":"在危險區域發現了倖存者。需要幫助嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 들이대길래 쳐버렸다만… 딱히 전투형 기체는 아니었던 것 같군.","JPN":"いきなり近づいてきたから思わず殴ってしまったが……戦闘型の機体ではなかったようだな。","ENG":"I hit it because it came up to me... but it doesn't seem like a combat drone.","TWN":"看到它突然沖過來就下意識還手了……但似乎並不是戰鬥型機體。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아, 그건 구급용 드론입니다.","JPN":"あ、それは救急用のドローンです。","ENG":"Oh. That's a first aid drone.","TWN":"喔，那是一架救護無人機。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아케론엔 일반적으로 통행이 불가능한 수감동이 많아서 응급상황에 대비해 이런 드론들이 오가는 작은 구멍이 있거든요.","JPN":"アケロンには通行不可の収容棟が沢山あるので、応急状況に備えてドローンが行き来できる小さな穴があるんですよ。","ENG":"Acheron holds many sections that are not traversable through ordinary means, so there are small holes that these drones travel through in case of an emergency.","TWN":"黃泉裡有很多無法通行的牢房，因此在緊急情況下，這些無人機會透過小型出入口飛進飛出。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼 말이야.","JPN":"じゃあ、さ。","ENG":"Then, does that mean...","TWN":"那麼。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"수감동에 피치못할 사고가 생기면 이것들이 알아서 죄수들을 찾아준다는 거지?","JPN":"収容棟に予想外の事故が起きたら、このロボットが囚人を探してくれるってこと？","ENG":"That these drones will find the prisoners if an accident occurs in the prison cells?","TWN":"如果牢房裡發生不可避免的意外，這些無人機會自動尋找囚犯，對嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};